// Script: generar_32_vacuna_anti_automatico.js
// Que hace: agrega "Vacuna aplicada" y "Antiparasitario aplicado" a la
// categoria Cuidados del registro diario. A diferencia de los otros 4
// cuidados, estos dos abren un mini-formulario al marcarlos (pidiendo
// solo el nombre, y tipo si es antiparasitario, con la proxima fecha
// como opcional), y al confirmar CREAN AUTOMATICAMENTE la fila en las
// tablas formales vacunas/antiparasitarios de Prevencion -- asi no hay
// que ir a Prevencion a registrarlo por separado.
//
// Si se cancela el mini-formulario sin completar el nombre, el check
// no queda marcado (no se crea nada).
//
//   1) app/registro-diario/page.tsx (REEMPLAZA el existente) -- las 2
//      opciones nuevas en Cuidados, el mini-modal, y la logica de
//      guardado automatico en Prevencion.
//
//   2) app/dashboard/page.tsx (REEMPLAZA el existente) -- estos 2
//      cuidados tambien aparecen en "Cuidados recientes" con su
//      "hace cuantos dias fue la ultima vez".
//
// IMPORTANTE: este script POR SI SOLO no es suficiente. Antes de
// correrlo hay que ejecutar 05_vacuna_anti_hoy.sql en un NUEVO snippet
// de Supabase (agrega 2 columnas booleanas mas a registros_diarios).
//
// Como correrlo: node generar_32_vacuna_anti_automatico.js
// Confirma "OK" para ambos archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/registro-diario/page.tsx', "");
escribir('app/dashboard/page.tsx', "");
